// Split the comma-separated ticker string into one item per ticker.
// Config values are forwarded on every item so downstream nodes stay stateless.
const cfg = $input.first().json;
const tickers = cfg.tickers
  .split(',')
  .map(t => t.trim().toUpperCase())
  .filter(Boolean);

console.log('[CONFIG] Scanning ' + tickers.length + ' tickers: ' + tickers.join(', '));

return tickers.map(ticker => ({
  json: {
    ticker,
    polygon_api_key:     cfg.polygon_api_key,
    grok_api_key:        cfg.grok_api_key,
    sentiment_threshold: cfg.sentiment_threshold,
    lookback_minutes:    cfg.lookback_minutes,
    sm_webhook:          cfg.sm_webhook,
    telegram_bot_token:  cfg.telegram_bot_token,
    telegram_chat_id:    cfg.telegram_chat_id
  }
}));

// Filter and Deduplicate Articles v2
// Changes from v1:
//   - Composite dedup key: ticker + article_id + published_utc (not bare ID)
//   - Daily reset at 8:30 AM ET — ensures morning economic news (CPI, PPI, jobs) always processes fresh
//   - Wider default lookback (60 min) so midday quiet periods don't silently drop valid recent news
//   - Detailed per-article logging: [NEW] vs [SKIP]

const state = $getWorkflowStaticData('global');
const nowMs  = Date.now();

// ── Daily Reset — 8:30 AM ET ─────────────────────────────────────────────────
// If today's date (ET) is newer than the last reset date stored, and the
// current ET time is at or past 08:30, clear the entire seen-article cache.
// This guarantees pre-market / opening-bell news is never suppressed.
const nowET      = new Date(nowMs);
const etDateStr  = nowET.toLocaleDateString('en-US', { timeZone: 'America/New_York' });
const etTimeStr  = nowET.toLocaleTimeString('en-US', {
  timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit', hour12: false
});
const etHHMM = etTimeStr.replace(':', '');  // e.g. "0835"
const resetKey = etDateStr + '_reset';       // e.g. "4/6/2026_reset"

const pastResetTime = parseInt(etHHMM) >= 830;  // at or after 08:30 ET

if (pastResetTime && state._lastDailyReset !== resetKey) {
  const oldSize = Object.keys(state.seenArticleIds || {}).length;
  state.seenArticleIds = {};
  state._lastDailyReset = resetKey;
  console.log('[DEDUPE] Daily reset at 8:30 AM ET — cleared ' + oldSize + ' cached IDs for ' + etDateStr);
}

if (!state.seenArticleIds) state.seenArticleIds = {};

// ── Prune Stale Entries (4 hours — generous, daily reset handles the rest) ───
const PRUNE_MS = 4 * 60 * 60 * 1000;  // 4 hours
let pruned = 0;
for (const key of Object.keys(state.seenArticleIds)) {
  if (nowMs - state.seenArticleIds[key] > PRUNE_MS) {
    delete state.seenArticleIds[key];
    pruned++;
  }
}
if (pruned > 0) console.log('[DEDUPE] Pruned ' + pruned + ' stale entries (>4h old)');

// ── Process Articles ─────────────────────────────────────────────────────────
const newArticles = [];
let skipped = 0;

for (const item of $input.all()) {
  const data     = item.json;
  const articles = data.results || [];

  // Accept articles published within the last 60 min by default.
  // This is wider than v1's 10-min fallback so midday articles
  // (published 30–55 min ago) are not silently rejected.
  const lookbackMin = data.lookback_minutes || 60;
  const cutoffMs    = nowMs - lookbackMin * 60 * 1000;

  for (const a of articles) {
    const rawId  = a.id || a.article_url || '';
    if (!rawId) continue;

    // Composite dedup key: ticker + article_id + date-part of published_utc
    // Using date-part prevents a new-day rerun of an old article from being
    // treated as duplicate across session boundaries.
    const pubDay = (a.published_utc || '').substring(0, 10);  // "2026-04-06"
    const ticker = data.ticker || (a.tickers || [])[0] || '';
    const dedupeKey = ticker + '|' + rawId + '|' + pubDay;

    // Skip genuinely-already-processed articles
    if (state.seenArticleIds[dedupeKey]) {
      skipped++;
      console.log('[SKIP] ' + ticker + ' — "' + (a.title || rawId).substring(0, 60) + '" (already processed)');
      continue;
    }

    // Skip articles outside the lookback window
    const pubDate = new Date(a.published_utc || 0);
    if (pubDate.getTime() < cutoffMs) {
      console.log('[OLD]  ' + ticker + ' — "' + (a.title || rawId).substring(0, 60) + '" published ' + a.published_utc + ' (outside ' + lookbackMin + 'min window)');
      continue;
    }

    // Mark as seen immediately (prevents double-fire within same run or next run)
    state.seenArticleIds[dedupeKey] = nowMs;

    if (!ticker) continue;

    console.log('[NEW]  ' + ticker + ' — "' + (a.title || rawId).substring(0, 60) + '" published ' + a.published_utc);

    newArticles.push({
      json: {
        ticker,
        article_id:          rawId,
        title:               a.title || '',
        description:         (a.description || '').substring(0, 600),
        published_utc:       a.published_utc || '',
        article_url:         a.article_url   || '',
        source:              (a.publisher || {}).name || 'Polygon',
        grok_api_key:        data.grok_api_key,
        sentiment_threshold: data.sentiment_threshold,
        sm_webhook:          data.sm_webhook,
        telegram_bot_token:  data.telegram_bot_token,
        telegram_chat_id:    data.telegram_chat_id
      }
    });
  }
}

console.log(
  '[DEDUPE] Result: ' + newArticles.length + ' new | ' + skipped + ' skipped | ' +
  'cache size: ' + Object.keys(state.seenArticleIds).length
);

if (newArticles.length === 0) return [];
return newArticles;

// Grok Sentiment Scorer v3 — fixes "json property isn't an object" error
// The input item may contain a field named 'json' (e.g. from n8n internal wrapping).
// Strip that key before spreading to avoid the validation error.
// Mode: runOnceForEachItem

const GROK_KEY = 'REDACTED_XAI_API_KEY';
const GROK_URL = 'https://api.x.ai/v1/chat/completions';

const rawItem = $input.item.json;
// Remove 'json' key if present — prevents "json must point to an object" validation error
const { json: _j, ...item } = rawItem;

const ticker      = (item.ticker      || '').toUpperCase();
const title       = (item.title       || '').slice(0, 300);
const description = (item.description || '').slice(0, 500);

const systemPrompt =
  'You are a financial sentiment analyst. Output ONLY valid JSON: ' +
  '{"sentiment_score": <-1.0 to 1.0>, "sentiment_reason": "<one sentence>"}. No markdown.';

const userPrompt = 'Ticker: ' + ticker + '\nHeadline: ' + title + '\nDescription: ' + description;

let result;
try {
  result = await this.helpers.httpRequest({
    method: 'POST', url: GROK_URL,
    headers: { 'Authorization': 'Bearer ' + GROK_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model:'grok-3', messages:[{role:'system',content:systemPrompt},{role:'user',content:userPrompt}], temperature:0, max_tokens:120 }),
    json: true
  });
  console.log('[GROK SENT v3] ' + ticker + ' OK');
  return [{ json: { ...item, ...result, _grok_error: false } }];
} catch (e) {
  console.log('[GROK SENT v3] ERROR ' + ticker + ': ' + String(e.message).slice(0, 80));
  return [{ json: { ...item, choices:[{message:{content:'{"sentiment_score":0,"sentiment_reason":"error"}' }}], _grok_error:true, _grok_error_msg: String(e.message).slice(0,150) } }];
}

// Parse and Validate Score v2 — Robust JSON extraction
// v2 fixes: extract JSON by finding first { to last } in the response,
// handles Grok reasoning text before/after JSON, NaN/Infinity, extra whitespace.

const resp = $input.item.json;
const meta = $input.item.json;

let sentiment_score  = 0;
let sentiment_reason = '';
let parse_ok         = false;

try {
  const raw = ((resp.choices || [])[0]?.message?.content || '').trim();

  // Step 1: Strip markdown fences
  let clean = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  // Step 2: Extract JSON object by finding outermost { ... }
  // Handles Grok prepending reasoning text before the JSON blob
  const start = clean.indexOf('{');
  const end   = clean.lastIndexOf('}');
  if (start === -1 || end <= start) throw new Error('No JSON object found in response');
  const jsonStr = clean.slice(start, end + 1);

  // Step 3: Sanitise values that break JSON.parse (NaN, Infinity, undefined)
  const safe = jsonStr
    .replace(/:\s*NaN\b/g, ': 0')
    .replace(/:\s*Infinity\b/g, ': 1')
    .replace(/:\s*-Infinity\b/g, ': -1')
    .replace(/:\s*undefined\b/g, ': null');

  const parsed        = JSON.parse(safe);
  sentiment_score     = Math.max(-1.0, Math.min(1.0, parseFloat(parsed.sentiment_score) || 0));
  sentiment_reason    = String(parsed.sentiment_reason || '').substring(0, 200);
  parse_ok            = true;

} catch (err) {
  // Log the failure but do NOT throw — _skip=false allows pipeline to continue
  // with score=0 (neutral) rather than crashing the execution
  console.log('[PARSE v2 WARN] ' + (meta.ticker||'?') + ': ' + err.message);
}

console.log('[SCORE] ' + (meta.ticker||'?') + ': ' + sentiment_score.toFixed(2) +
  (parse_ok ? ' — ' + sentiment_reason.slice(0, 60) : ' (parse failed — neutral fallback)'));

return [{
  json: {
    ticker:              meta.ticker,
    title:               meta.title,
    published_utc:       meta.published_utc,
    article_url:         meta.article_url,
    source:              meta.source,
    sentiment_score,
    sentiment_reason,
    parse_ok,
    sentiment_threshold: meta.sentiment_threshold,
    sm_webhook:          meta.sm_webhook,
    telegram_bot_token:  meta.telegram_bot_token,
    telegram_chat_id:    meta.telegram_chat_id,
  }
}];
